from __future__ import annotations
import heapq
import itertools
from collections import deque, defaultdict
from dataclasses import dataclass, field
from typing import Any, Callable, Iterator


# ── Priority task queue ───────────────────────────────────────────────────────

@dataclass(order=False)
class Task:
    name: str
    priority: int = 5          # lower = more urgent
    payload: Any = None

_COUNTER = itertools.count()   # monotone tiebreaker

class PriorityTaskQueue:
    """Thread-unsafe priority queue suitable for single-threaded / async agents."""

    def __init__(self) -> None:
        self._heap: list[tuple[int, int, Task]] = []

    def push(self, task: Task) -> None:
        heapq.heappush(self._heap, (task.priority, next(_COUNTER), task))

    def pop(self) -> Task:
        if not self._heap:
            raise IndexError("pop from empty queue")
        _, _, task = heapq.heappop(self._heap)
        return task

    def peek(self) -> Task:
        return self._heap[0][2]

    def __len__(self) -> int:
        return len(self._heap)

    def __bool__(self) -> bool:
        return bool(self._heap)


# ── Dependency graph with topological execution ───────────────────────────────

class TaskGraph:
    """DAG of tasks; executes them in dependency order via Kahn's algorithm."""

    def __init__(self) -> None:
        self._deps: dict[str, list[str]] = defaultdict(list)  # node → prerequisites
        self._nodes: set[str] = set()

    def add_task(self, name: str, depends_on: list[str] | None = None) -> None:
        self._nodes.add(name)
        for dep in (depends_on or []):
            self._nodes.add(dep)
            self._deps[name].append(dep)

    def execution_order(self) -> list[str]:
        """Return a valid topological ordering, or raise if a cycle exists."""
        in_degree: dict[str, int] = {n: 0 for n in self._nodes}
        # build reverse edges: dep → dependents
        successors: dict[str, list[str]] = defaultdict(list)
        for node, prereqs in self._deps.items():
            for dep in prereqs:
                successors[dep].append(node)
                in_degree[node] += 1

        ready: deque[str] = deque(n for n, d in in_degree.items() if d == 0)
        order: list[str] = []

        while ready:
            node = ready.popleft()
            order.append(node)
            for succ in successors[node]:
                in_degree[succ] -= 1
                if in_degree[succ] == 0:
                    ready.append(succ)

        if len(order) != len(self._nodes):
            raise ValueError("Cycle detected in task graph")
        return order


# ── Smoke test ────────────────────────────────────────────────────────────────

if __name__ == "__main__":
    # Priority queue demo
    q: PriorityTaskQueue = PriorityTaskQueue()
    q.push(Task("bg_index",     priority=5))
    q.push(Task("draft",        priority=3))
    q.push(Task("critical_err", priority=1))

    while q:
        t = q.pop()
        print(f"[{t.priority}] {t.name}")
    # Prints: [1] critical_err, [3] draft, [5] bg_index

    # Graph topo-sort demo
    g = TaskGraph()
    g.add_task("publish",  depends_on=["review"])
    g.add_task("review",   depends_on=["draft"])
    g.add_task("draft",    depends_on=["research"])
    g.add_task("research")
    print(g.execution_order())
    # ['research', 'draft', 'review', 'publish']

import hashlib, json
from collections import deque
from typing import Any, Callable

# Tool registry: name → handler
_TOOLS: dict[str, Callable[..., Any]] = {}

def register(name: str):
    def decorator(fn):
        _TOOLS[name] = fn
        return fn
    return decorator

@register("search")
def search(query: str) -> str:
    return f"[results for: {query}]"   # stub — real impl calls an API

@register("summarize")
def summarize(text: str) -> str:
    return text[:120] + "..."

# Memoization cache: serialized args → result
_CACHE: dict[str, Any] = {}

def dispatch(name: str, **kwargs: Any) -> Any:
    if name not in _TOOLS:
        raise KeyError(f"Unknown tool: {name}")
    cache_key = hashlib.sha256(
        json.dumps({"tool": name, "args": kwargs}, sort_keys=True).encode()
    ).hexdigest()
    if cache_key in _CACHE:
        print(f"  cache hit: {name}")
        return _CACHE[cache_key]
    result = _TOOLS[name](**kwargs)
    _CACHE[cache_key] = result
    return result

# Driver
calls = deque([
    ("search",    {"query": "climate change 2024"}),
    ("summarize", {"text": "Global temperatures rose..."}),
    ("search",    {"query": "climate change 2024"}),   # cache hit
])

while calls:
    tool_name, args = calls.popleft()
    print(dispatch(tool_name, **args))

graph = {"A": ["B"], "B": ["C"], "C": ["A"]}  # cycle A→B→C→A

# BAD — infinite loop
def bad_dfs(node, graph):
    print(node)
    for nb in graph.get(node, []):
        bad_dfs(nb, graph)      # revisits A forever

# GOOD
def good_dfs(node, graph, visited=None):
    if visited is None:
        visited = set()
    if node in visited:
        return
    visited.add(node)
    print(node)
    for nb in graph.get(node, []):
        good_dfs(nb, graph, visited)

def has_cycle(graph: dict[str, list[str]]) -> bool:
    """Return True if graph contains a directed cycle."""
    WHITE, GRAY, BLACK = 0, 1, 2
    color = {n: WHITE for n in graph}

    def dfs(node: str) -> bool:
        color[node] = GRAY
        for nb in graph.get(node, []):
            if color[nb] == GRAY:
                return True
            if color[nb] == WHITE and dfs(nb):
                return True
        color[node] = BLACK
        return False

    return any(dfs(n) for n in graph if color[n] == WHITE)
